B.pX=s(["text","multiline","number","phone","datetime","emailAddress","url","visiblePassword","name","address","none","webSearch","twitter"],t.s)
B.pY=s(["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"],t.s)
B.O0=s(["J\u2019ai sacrifi\xe9 ma main pour encha\xeener un loup.","Je suis le dieu manchot de la justice et de la guerre h\xe9ro\xefque.","Mon nom est synonyme de courage."],t.s)
B.Sn=new A.cx("TYR",B.O0)
B.OU=s(["J\u2019ai \xe9chang\xe9 un \u0153il contre la sagesse.","Mes deux corbeaux parcourent le monde pour m\u2019informer.","Je suis le P\xe8re de Tout, r\xe9gnant depuis Asgard."],t.s)
B.Sh=new A.cx("ODIN",B.OU)
B.P1=s(["Mon char est tir\xe9 par des boucs.","Je suis le protecteur de Midgard et le fils d\u2019Odin.","Le tonnerre gronde quand je lance mon marteau."],t.s)
B.Sj=new A.cx("THOR",B.P1)
B.Nf=s(["Je suis le p\xe8re de monstres et le ma\xeetre de la tromperie.","Mon sang s\u2019est m\xeal\xe9 \xe0 celui d\u2019Odin.","Je change de forme comme je change d\u2019avis."],t.s)
B.Si=new A.cx("LOKI",B.Nf)
B.OJ=s(["Je pleure des larmes d\u2019or pour mon \xe9poux parti.","Je r\xe8gne sur le F\xf3lkvangr et re\xe7ois la moiti\xe9 des guerriers morts.","Mon collier, Br\xedsingamen, est le plus beau des tr\xe9sors."],t.s)
B.Sm=new A.cx("FREYA",B.OJ)
B.NI=s(["Je connais le destin de tous, mais je garde le silence.","Je suis l\u2019\xe9pouse d\u2019Odin et la reine d\u2019Asgard.","J\u2019ai pleur\xe9 la mort de mon fils lumineux."],t.s)
B.Sc=new A.cx("FRIGG",B.NI)
B.ND=s(["Ma m\xe2choire, une fois ouverte, touche le ciel et la terre.","Les dieux m\u2019ont encha\xeen\xe9 par la ruse avec un ruban de soie.","Je d\xe9vorerai Odin lors de la derni\xe8re bataille."],t.s)
B.Se=new A.cx("FENRIR",B.ND)
B.MQ=s(["Je suis la forteresse des dieux Ases.","Mes murs ont \xe9t\xe9 construits par un g\xe9ant et son cheval.","Le pont arc-en-ciel m\xe8ne \xe0 mes portes."],t.s)
B.S8=new A.cx("ASGARD",B.MQ)
B.Oz=s(["Chaque matin, je pars pour ne revenir qu\u2019au soir.","Je suis la Pens\xe9e qui vole pour le P\xe8re de Tout.","Mon fr\xe8re est la M\xe9moire."],t.s)
B.Sr=new A.cx("HUGINN",B.Oz)
B.OM=s(["Je suis un pont de feu gard\xe9 par un dieu vigilant.","Mes trois couleurs relient le monde des hommes \xe0 celui des dieux.","Je me briserai sous le poids des g\xe9ants \xe0 la fin des temps."],t.s)
B.So=new A.cx("BIFROST",B.OM)
B.Ov=s(["Je reviens toujours \xe0 la main de mon ma\xeetre.","Mon vol dans le ciel est le son du tonnerre.","Je suis le broyeur, terreur des g\xe9ants."],t.s)
B.Sf=new A.cx("MJOLNIR",B.Ov)
B.P_=s(["Je suis le royaume des mortels.","Un serpent g\xe9ant entoure mes c\xf4tes.","Je suis prot\xe9g\xe9 par le fils d\u2019Odin au marteau."],t.s)
B.S6=new A.cx("MIDGARD",B.P_)
B.Ow=s(["Mon toit est couvert de boucliers dor\xe9s.","Ici, les guerriers d\u2019\xe9lite festoient et combattent chaque jour.","Je suis le grand hall d\u2019Odin pour les morts valeureux."],t.s)
B.Sb=new A.cx("VALHALLA",B.Ow)
B.Na=s(["Je suis la lance qui ne manque jamais sa cible.","Mon propri\xe9taire s\u2019est pendu \xe0 un arbre avec moi dans le flanc.","Un serment pr\xeat\xe9 sur ma pointe est inviolable."],t.s)
B.Sp=new A.cx("GUNGNIR",B.Na)
B.N7=s(["Je suis le cr\xe9puscule des dieux.","Le soleil deviendra noir et la terre sombrera dans la mer.","Je suis une fin, mais aussi un nouveau commencement."],t.s)
B.Sq=new A.cx("RAGNAROK",B.N7)
B.OD=s(["Mes racines unissent trois mondes.","Je suis l\u2019Arbre du Monde, un fr\xeane \xe9ternel.","Un aigle, un \xe9cureuil et un dragon vivent en moi."],t.s)
B.Sd=new A.cx("YGGDRASIL",B.OD)
B.O9=s(["Nous chevauchons les cieux, choisissant les morts au combat.","Nous servons Odin, portant les h\xe9ros au Valhalla.","Nos noms r\xe9sonnent sur les champs de bataille."],t.s)
B.Ss=new A.cx("VALKYRIES",B.O9)
B.NG=s(["Je suis le royaume des g\xe9ants, au-del\xe0 de Midgard.","Mes montagnes sont froides et mes habitants redoutables.","C\u2019est ici que Thor vient souvent chercher querelle."],t.s)
B.S7=new A.cx("JOTUNHEIM",B.NG)
B.NZ=s(["Mes forges r\xe9sonnent des coups de marteau.","Je suis le royaume souterrain des artisans du m\xe9tal.","C\u2019est ici que naissent les plus grands tr\xe9sors des dieux.","Mes habitants fuient la lumi\xe8re du soleil."],t.s)
B.Sl=new A.cx("NIDAVELLIR",B.NZ)
B.OX=s(["Je suis la source de toutes les rivi\xe8res, au c\u0153ur de Niflheim.","Mon chaudron bouillonne, et mes eaux g\xe8lent tout sur leur passage.","C\u2019est de moi que naissent les onze fleuves d\u2019\xc9liv\xe1gar."],t.s)
B.Sg=new A.cx("HVERGELMIR",B.OX)
